function load$GridVoucherDetail$(g) {
  g.add_itemValueChanged(onChange$GridVoucherDetail$);
  g.add_onResponseComplete(on$GridVoucherDetail$ResponseComplete);
  g.add_commandEvent(on$GridVoucherDetail$ExecuteCommand);
  g.$a = {
    tien: '[tien]:=[tien_nt]*[$ty_gia]',
&ScriptTaxGridDetailDeclareArray;
    t_tien_nt: ['t_tien_nt', 'tien_nt'],
    t_tien: ['t_tien', 'tien'],
    t_tt: '[t_tt]:=[t_tien]+[t_thue]',
    t_tt_nt: '[t_tt_nt]:=[t_tien_nt]+[t_thue_nt]'
  };
  udf$Detail$(g);
}
/* <flatten type="Javascript"> */
function dispose$GridVoucherDetail$(g) {
  g.$a = null;
  try {g.remove_commandEvent(on$GridVoucherDetail$ExecuteCommand);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$GridVoucherDetail$);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridVoucherDetail$ResponseComplete);} catch (ex) {}
}
/* </flatten> */
function onChange$GridVoucherDetail$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'tien_nt':
      g.validExpression(o, [g.$a.tien, g.$a.thue_nt, g.$a.thue2, g.$a.tien_tt_nt, g.$a.tien_tt], [g.$a.t_tien_nt2, g.$a.t_tien2, g.$a.t_thue1_nt, g.$a.t_thue1], [g.$a.t_thue_nt, g.$a.t_thue, g.$a.t_tt_nt, g.$a.t_tt]);
      break;
    case 'tien':
       g.validExpression(o, [g.$a.thue2, g.$a.tien_tt], [g.$a.t_tien2, g.$a.t_thue1], [g.$a.t_thue, g.$a.t_tt]);
      break;
&ScriptTaxGridDetailValid;
    default:
      break;
  }
}

function on$GridVoucherDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  switch (action) {
    case 'AfterRemoveRow':
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'Check':
&ScriptTaxGridDetailCheck;
	    if ($func.trim(f.getItemValue('loai_ct')) == '3') g.validRowExpression('ma_kh_i', '([tk_cn] != 1) || ([tk_cn] == 1 && [ma_kh_i] != "")');
      break;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function onChange$GridVoucherDetail$DebitAccount(o) {o.grid.request(o, 'GetAccountType', 'AccountType', ['tk_no'], o);}
/* </flatten> */
function on$GridVoucherDetail$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm;
  switch (context) {
    case 'AccountType':
      g.setItemGridBehavior(o, [['tk_cn', result[0].Value, '', false]]);
      break;
&ScriptTaxGridDetailResponse;
    default:
      break;
  }
}

&ScriptTaxGridDetailFunction;







